const raw = $input.first().json.choices[0].message.content;
let ai;
try {
  ai = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  ai = match ? JSON.parse(match[0]) : { telegram: raw, email_subject: 'تم استلام طلبك', email_html: raw };
}
const body = $('Webhook').first().json.body;
return [{ json: {
  telegram_msg: ai.telegram || '',
  email_subject: ai.email_subject || 'تم استلام طلبك — Vortex Digital',
  email_html: ai.email_html || '',
  name: body.name, email: body.email,
  phone: body.phone, role: body.role, service: body.service
}}];
